#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main() {
    srand(time(NULL));
    int secret = rand() % 100 + 1;
    int guess = 0;
    while (guess != secret) {
        printf("Guess (1-100): ");
        scanf("%d", &guess);
        if (guess < secret) printf("Higher!\n");
        else if (guess > secret) printf("Lower!\n");
    }
    printf("You got it!\n");
    return 0;
}
